    // Fill first column (only movement from above)
    for (int i = 1; i < m; i++) {
        int currentVal = (int)grid[i][0];
        for (const int y of dp[i - 1][0]) {
            dp[i][0].insert(y ^ currentVal);
        }
    }

    // Fill the rest of the DP table
    for (int i = 1; i < m; i++) {
        for (int j = 1; j < n; j++) {
            int currentVal = (int)grid[i][j];

            // From above (i-1, j)
            for (const int x of dp[i - 1][j]) {
                dp[i][j].insert(x ^ currentVal);
            }

            // From left (i, j-1)
            for (const int y of dp[i][j - 1]) {
                dp[i][j].insert(y ^ currentVal);
            }
        }
    }

    // The result is the minimum value in the set at the bottom-right corner
    const set<int>& finalSet = dp[m - 1][n - 1];

    if (finalSet.empty()) {
        // This should not happen given the problem constraints
        return 0; 
    }

    // Since std::set iterates in sorted order, the first element is the minimum.
    int minXor = *finalSet.begin();

    return (long long)minXor;
