#include <vector>
#include <algorithm>
#include <cmath>

long long solve(std::vector<std::vector<long long>> grid) {
    int M = grid.size();
    int N = grid[0].size();
    const int V_MAX = 1024;

    // dp[i][j][k] is true if XOR sum k is reachable at (i, j)
    std::vector<std::vector<std::vector<bool>>> dp(M, 
        std::vector<std::vector<bool>>(N, std::vector<bool>(V_MAX, false)));

    // Base Case (0, 0)
    int initial_xor = grid[0][0];
    dp[0][0][initial_xor] = true;

    // Fill DP table
    for (int i = 0; i < M; ++i) {
        for (int j = 0; j < N; ++j) {
            if (i == 0 && j == 0) continue;

            int G = grid[i][j]; // Current cell value XOR contribution

            // 1. Check predecessor from above (i-1, j)
            if (i > 0) {
                for (int k = 0; k < V_MAX; ++k) {
                    if (dp[i - 1][j][k]) {
                        int new_xor = k ^ G;
                        dp[i][j][new_xor] = true;
                    }
                }
            }

            // 2. Check predecessor from left (i, j-1)
            if (j > 0) {
                for (int k = 0; k < V_MAX; ++k) {
                    if (dp[i][j - 1][k]) {
                        int new_xor = k ^ G;
                        dp[i][j][new_xor] = true;
                    }
                }
            }
        }
    }

    // Find the minimum reachable XOR sum at (M-1, N-1)
    for (int k = 0; k < V_MAX; ++k) {
        if (dp[M - 1][N - 1][k]) {
            return k;
        }
    }

    // Should not be reached given the constraints
    return 0; 
}

