function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // DP[i][j] stores a Set of all possible XOR sums reaching (i, j).
    const dp = Array(m).fill(0).map(() => Array(n).fill(null).map(() => new Set()));

    // Base Case
    dp[0][0].add(grid[0][0]);

    // Fill first row (only movement from the left)
    for (let j = 1; j < n; j++) {
        for (const x of dp[0][j - 1]) {
            dp[0][j].add(x ^ grid[0][j]);
        }
    }

    // Fill first column (only movement from above)
    for (let i = 1; i < m; i++) {
        for (const y of dp[i - 1][0]) {
            dp[i][0].add(y ^ grid[i][0]);
        }
    }

    // Fill the rest of the DP table
    for (let i = 1; i < m; i++) {
        for (let j = 1; j < n; j++) {
            const currentVal = grid[i][j];

            // From above (i-1, j)
            for (const x of dp[i - 1][j]) {
                dp[i][j].add(x ^ currentVal);
            }

            // From left (i, j-1)
            for (const y of dp[i][j - 1]) {
                dp[i][j].add(y ^ currentVal);
            }
        }
    }

    // The result is the minimum value in the set at the bottom-right corner
    const finalSet = dp[m - 1][n - 1];

    let minXor = Infinity;
    for (const xorSum of finalSet) {
        if (xorSum < minXor) {
            minXor = xorSum;
        }
    }

    return minXor;
}

